完整代码：

<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>贪食蛇游戏</title>
    <style>
        body {
            margin: 0;
            padding: 0;
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
            background: linear-gradient(180deg, #1a1a2e 0%, #16213e 100%);
            font-family: 'PingFang SC', 'Microsoft YaHei', sans-serif;
        }
        canvas {
            max-width: 100%;
            height: auto;
            display: block;
            margin: 0 auto;
            border-radius: 12px;
            box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);
        }
    </style>
</head>
<body>
    <canvas id="gameCanvas"></canvas>
    <script>
        const canvas = document.getElementById('gameCanvas');
        const ctx = canvas.getContext('2d');

        // 设置 canvas 尺寸
        canvas.width = 360;
        canvas.height = 640;

        // 游戏常量
        const gridSize = 20;
        const gridWidth = Math.floor(canvas.width / gridSize);
        const gridHeight = Math.floor(canvas.height / gridSize);
        const moveInterval = 150; // 毫秒

        // 游戏状态
        let gameState = 'menu'; // menu, playing, paused, gameover
        let score = 0;
        let highScore = localStorage.getItem('snakeHighScore') || 0;

        // 蛇和食物
        let snake = [];
        let direction = { x: 1, y: 0 };
        let nextDirection = { x: 1, y: 0 };
        let food = { x: 0, y: 0 };

        // 时间控制
        let lastTime = 0;
        let moveTimer = 0;

        // 初始化游戏
        function initGame() {
            snake = [{ x: Math.floor(gridWidth / 2), y: Math.floor(gridHeight / 2) }];
            direction = { x: 1, y: 0 };
            nextDirection = { x: 1, y: 0 };
            score = 0;
            spawnFood();
        }

        // 生成食物
        function spawnFood() {
            let valid = false;
            while (!valid) {
                food.x = Math.floor(Math.random() * gridWidth);
                food.y = Math.floor(Math.random() * gridHeight);
                valid = true;
                for (let segment of snake) {
                    if (segment.x === food.x && segment.y === food.y) {
                        valid = false;
                        break;
                    }
                }
            }
        }

        // 输入处理
        function handleInput(key, pressed) {
            if (!pressed) return; // 只处理按下事件

            if (gameState === 'menu') {
                if (key === ' ' || key === 'Enter') {
                    gameState = 'playing';
                    initGame();
                }
            } else if (gameState === 'playing') {
                switch (key) {
                    case 'ArrowUp':
                    case 'w':
                    case 'W':
                        if (direction.y !== 1) nextDirection = { x: 0, y: -1 };
                        break;
                    case 'ArrowDown':
                    case 's':
                    case 'S':
                        if (direction.y !== -1) nextDirection = { x: 0, y: 1 };
                        break;
                    case 'ArrowLeft':
                    case 'a':
                    case 'A':
                        if (direction.x !== 1) nextDirection = { x: -1, y: 0 };
                        break;
                    case 'ArrowRight':
                    case 'd':
                    case 'D':
                        if (direction.x !== -1) nextDirection = { x: 1, y: 0 };
                        break;
                    case 'p':
                    case 'P':
                        gameState = 'paused';
                        break;
                }
            } else if (gameState === 'paused') {
                if (key === 'p' || key === 'P') {
                    gameState = 'playing';
                }
            } else if (gameState === 'gameover') {
                if (key === ' ' || key === 'Enter') {
                    gameState = 'menu';
                }
            }
        }

        // 更新游戏逻辑
        function update(deltaTime) {
            if (gameState === 'playing') {
                moveTimer += deltaTime;
                if (moveTimer >= moveInterval) {
                    moveTimer = 0;
                    direction = nextDirection;

                    // 移动蛇
                    const head = { x: snake[0].x + direction.x, y: snake[0].y + direction.y };

                    // 检查碰撞
                    if (head.x < 0 || head.x >= gridWidth || head.y < 0 || head.y >= gridHeight) {
                        gameOver();
                        return;
                    }

                    for (let segment of snake) {
                        if (segment.x === head.x && segment.y === head.y) {
                            gameOver();
                            return;
                        }
                    }

                    snake.unshift(head);

                    // 检查是否吃到食物
                    if (head.x === food.x && head.y === food.y) {
                        score += 10;
                        if (score > highScore) {
                            highScore = score;
                            localStorage.setItem('snakeHighScore', highScore);
                        }
                        spawnFood();
                    } else {
                        snake.pop();
                    }
                }
            }
        }

        // 游戏结束
        function gameOver() {
            gameState = 'gameover';
        }

        // 渲染游戏
        function render() {
            // 清除 canvas
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // 绘制背景（��选，因为 body 有背景，但为了圆角，绘制一个圆角矩形）
            ctx.fillStyle = 'rgba(26, 26, 46, 0.9)'; // 半透明深色，匹配 body 背景
            roundRect(ctx, 0, 0, canvas.width, canvas.height, 12);
            ctx.fill();

            if (gameState === 'menu') {
                drawMenu();
            } else if (gameState === 'playing' || gameState === 'paused') {
                drawGame();
                if (gameState === 'paused') {
                    drawPaused();
                }
            } else if (gameState === 'gameover') {
                drawGameOver();
            }
        }

        // 绘制圆角矩形
        function roundRect(ctx, x, y, width, height, radius) {
            ctx.beginPath();
            ctx.moveTo(x + radius, y);
            ctx.lineTo(x + width - radius, y);
            ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
            ctx.lineTo(x + width, y + height - radius);
            ctx.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
            ctx.lineTo(x + radius, y + height);
            ctx.quadraticCurveTo(x, y + height, x, y + height - radius);
            ctx.lineTo(x, y + radius);
            ctx.quadraticCurveTo(x, y, x + radius, y);
            ctx.closePath();
        }

        // 绘制菜单
        function drawMenu() {
            ctx.fillStyle = '#ffffff';
            ctx.font = '30px PingFang SC, Microsoft YaHei, sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText('贪食蛇游戏', canvas.width / 2, canvas.height / 2 - 50);

            ctx.font = '20px PingFang SC, Microsoft YaHei, sans-serif';
            ctx.fillText('按空格键开始游戏', canvas.width / 2, canvas.height / 2 + 20);

            ctx.fillStyle = '#4fd1c5';
            ctx.fillText('最高分: ' + highScore, canvas.width / 2, canvas.height / 2 + 70);
        }

        // 绘制游戏
        function drawGame() {
            // 绘制得分
            ctx.fillStyle = '#ffffff';
            ctx.font = '20px PingFang SC, Microsoft YaHei, sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText('得分: ', canvas.width / 2, 30);
            ctx.fillStyle = '#4fd1c5';
            ctx.fillText(score, canvas.width / 2 + 40, 30);

            // 绘制食物
            ctx.fillStyle = '#ff6b6b';
            ctx.fillRect(food.x * gridSize, food.y * gridSize, gridSize, gridSize);

            // 绘制蛇
            ctx.fillStyle = '#4fd1c5';
            for (let segment of snake) {
                ctx.fillRect(segment.x * gridSize, segment.y * gridSize, gridSize, gridSize);
            }

            // 绘制网格线（可选，为了视觉效果）
            ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
            ctx.lineWidth = 1;
            for (let i = 0; i <= gridWidth; i++) {
                ctx.beginPath();
                ctx.moveTo(i * gridSize, 0);
                ctx.lineTo(i * gridSize, canvas.height);
                ctx.stroke();
            }
            for (let j = 0; j <= gridHeight; j++) {
                ctx.beginPath();
                ctx.moveTo(0, j * gridSize);
                ctx.lineTo(canvas.width, j * gridSize);
                ctx.stroke();
            }
        }

        // 绘制暂停界面
        function drawPaused() {
            ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            ctx.fillStyle = '#ffffff';
            ctx.font = '30px PingFang SC, Microsoft YaHei, sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText('游戏暂停', canvas.width / 2, canvas.height / 2 - 20);
            ctx.font = '20px PingFang SC, Microsoft YaHei, sans-serif';
            ctx.fillText('按 P 键继续', canvas.width / 2, canvas.height / 2 + 20);
        }

        // 绘制游戏结束界面
        function drawGameOver() {
            ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            ctx.fillStyle = '#ffffff';
            ctx.font = '30px PingFang SC, Microsoft YaHei, sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText('游戏结束', canvas.width / 2, canvas.height / 2 - 50);

            ctx.font = '20px PingFang SC, Microsoft YaHei, sans-serif';
            ctx.fillText('得分: ' + score, canvas.width / 2, canvas.height / 2);
            ctx.fillStyle = '#4fd1c5';
            ctx.fillText('最高分: ' + highScore, canvas.width / 2, canvas.height / 2 + 40);

            ctx.fillStyle = '#ffffff';
            ctx.fillText('按空格键返回菜单', canvas.width / 2, canvas.height / 2 + 100);
        }

        // 游戏循环
        function gameLoop(timestamp) {
            const deltaTime = timestamp - lastTime;
            lastTime = timestamp;

            update(deltaTime);
            render();

            requestAnimationFrame(gameLoop);
        }

        // 事件监听
        document.addEventListener('keydown', (event) => {
            handleInput(event.key, true);
        });

        // 开始游戏循环
        lastTime = performance.now();
        requestAnimationFrame(gameLoop);
    </script>
</body>
